59тЖТ  const playAlert = (signalType) => {
60тЖТ    try {
61тЖТ      const ctx = new (window.AudioContext || window.webkitAudioContext)();
62тЖТ      const osc = ctx.createOscillator();
63тЖТ      const gain = ctx.createGain();
64тЖТ      osc.connect(gain);
65тЖТ      gain.connect(ctx.destination);
66тЖТ      gain.gain.value = 0.3;
67тЖТ      if (signalType === 'ELECTRIC') { osc.frequency.value = 660; osc.type = 'sawtooth'; }
68тЖТ      else if (signalType === 'ASNOVA') { osc.frequency.value = 440; osc.type = 'triangle'; }
69тЖТ      else { osc.frequency.value = 520; osc.type = 'sine'; }
70тЖТ      osc.start();
71тЖТ      gain.gain.exponentialRampToValueAtTime(0.001, ctx.currentTime + 1.5);
72тЖТ      osc.stop(ctx.currentTime + 1.5);
73тЖТ    } catch (e) {}
74тЖТ  };
75тЖТ
76тЖТ  const fetchCalls = async () => {
77тЖТ    try {
78тЖТ      const res = await fetch(`${API}/mechanic-calls`, { headers });
79тЖТ      if (res.ok) {
80тЖТ        const data = await res.json();
81тЖТ        const newPending = data.filter(c => c.status === 'PENDING');
82тЖТ        const oldPending = prevCallsRef.current.filter(c => c.status === 'PENDING');
83тЖТ        if (newPending.length > oldPending.length) {
84тЖТ          const newCall = newPending.find(nc => !oldPending.some(oc => oc.id === nc.id));
85тЖТ          if (newCall) playAlert(newCall.signal_type || 'MECHANIC');
86тЖТ        }
87тЖТ        prevCallsRef.current = data;
88тЖТ        setCalls(data);
89тЖТ      }
90тЖТ    } catch (e) {}
91тЖТ  };
92тЖТ
93тЖТ  useEffect(() => {
94тЖТ    fetchCalls();
