151тЖТ    }
152тЖТ  };
153тЖТ
154тЖТ  const handleSignalChange = (type) => {
**155тЖТ    setCallForm({ ...callForm, signal_type: type });
156тЖТ    setSelectedReasons([]);
157тЖТ    setCustomReason('');
