383тЖТ
384тЖТ      {/* Attendance / Tabel Section */}
385тЖТ      {showAttendance && (
386тЖТ        <div style={formCardStyle}>
387тЖТ          <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '1rem' }}>
