422тЖТ                        const day = i + 1;
423тЖТ                        const dateStr = `${attendanceMonth}-${String(day).padStart(2, '0')}`;
424тЖТ                        const status = getAttendanceStatus(op.id, dateStr);
425тЖТ                        if (status === 'PRESENT') presentCount++;
426тЖТ                        const isToday = today.getFullYear() === y && (today.getMonth() + 1) === m && today.getDate() === day;
