429тЖТ                            <div style={{ display: 'flex', gap: '1px', justifyContent: 'center' }}>
430тЖТ                              <button onClick={() => handleSetAttendance(op.id, dateStr, status === 'PRESENT' ? '' : 'PRESENT')}
431тЖТ                                style={{
432тЖТ                                  width: '14px', height: '14px', borderRadius: '3px', border: 'none', cursor: 'pointer', fontSize: '0.5rem', padding: 0,
433тЖТ                                  background: status === 'PRESENT' ? '#22c55e' : 'rgba(255,255,255,0.05)',
434тЖТ                                  color: status === 'PRESENT' ? '#fff' : 'var(--text-muted)'
435тЖТ                                }}>+</button>
436тЖТ                              <button onClick={() => handleSetAttendance(op.id, dateStr, status === 'ABSENT' ? '' : 'ABSENT')}
437тЖТ                                style={{
438тЖТ                                  width: '14px', height: '14px', borderRadius: '3px', border: 'none', cursor: 'pointer', fontSize: '0.5rem', padding: 0,
439тЖТ                                  background: status === 'ABSENT' ? '#ef4444' : 'rgba(255,255,255,0.05)',
440тЖТ                                  color: status === 'ABSENT' ? '#fff' : 'var(--text-muted)'
441тЖТ                                }}>-</button>
442тЖТ                              <button onClick={() => handleSetAttendance(op.id, dateStr, status === 'REST' ? '' : 'REST')}
443тЖТ                                style={{
444тЖТ                                  width: '14px', height: '14px', borderRadius: '3px', border: 'none', cursor: 'pointer', fontSize: '0.5rem', padding: 0,
445тЖТ                                  background: status === 'REST' ? '#f59e0b' : 'rgba(255,255,255,0.05)',
446тЖТ                                  color: status === 'REST' ? '#fff' : 'var(--text-muted)'
447тЖТ                                }}>D</button>
448тЖТ                            </div>
449тЖТ                          </td>
450тЖТ                        );
451тЖТ                      })}
452тЖТ                      <td style={{ ...tdStyle, textAlign: 'center', fontWeight: 700, color: '#22c55e' }}>{presentCount}</td>
453тЖТ                    </tr>
454тЖТ                  );
455тЖТ                })}
456тЖТ              </tbody>
457тЖТ            </table>
458тЖТ          </div>
459тЖТ          <div style={{ marginTop: '8px', display: 'flex', gap: '12px', fontSize: '0.65rem', color: 'var(--text-muted)' }}>
460тЖТ            <span><span style={{ color: '#22c55e', fontWeight: 700 }}>+</span> = Ishga keldi</span>
461тЖТ            <span><span style={{ color: '#ef4444', fontWeight: 700 }}>-</span> = Kelmadi</span>
462тЖТ            <span><span style={{ color: '#f59e0b', fontWeight: 700 }}>D</span> = Dam olish</span>
463тЖТ          </div>
464тЖТ        </div>
465тЖТ      )}
466тЖТ
467тЖТ      {/* Workers by Position */}
468тЖТ      {POSITIONS.map(pos => {
469тЖТ        const workers = operatorsByPosition[pos];
